#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e5+5;
struct line{
    int st,t1,ed,t2;
}ln[N];
bool operator < (const line &A,const line &B){
    if(A.t1!=B.t1)return A.t1>B.t1;
    if(A.t2!=B.t2)return A.t2>B.t2;
    return (A.ed<B.ed);
}
int n,m,a[N],dp[N];
set<line> to[N];
queue<pii> q;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++)
        ln[i].st=read(),ln[i].t1=read(),
        ln[i].ed=read(),ln[i].t2=read(),
        to[ln[i].st].isr(ln[i]);
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=1;i<=n;i++)dp[i]=0x3f3f3f3f;
    dp[1]=0;q.push({1,0});
    while(!q.empty()){
        auto [u,tim]=q.front();
        //cout<<"["<<u<<","<<tim<<"]\n";
        int xy=(u==1?0:tim+a[u]);q.pop();
        auto id=to[u].begin();
        while(id!=to[u].end()){
            auto [st,t1,ed,t2]=(*id);
            //cout<<"st "<<t1<<" ed "<<t2<<"  "<<u<<"->"<<ed<<"\n";
            if(st!=u){++id;continue;}
            if(t1<xy)break;
            if(t2>=dp[ed]){
                auto nxt=id;++nxt;
                to[u].erase(id);id=nxt;
                continue;
            }
            dp[ed]=t2,q.push({ed,t2});
            auto nxt=id;++nxt;
            to[u].erase(id);id=nxt;
        }
    }for(int i=1;i<=n;i++)
        cout<<(dp[i]==0x3f3f3f3f?-1:dp[i])<<"\n";
    return 0;
}
/*

Bessie 是从 1 出发的，抵达 i 的时间一定是 s[j] 中的一个，且 d[j]=i。
显然不能建图，不然图很可能成为平方级别，会炸掉。
咋办呢？我们发现抵达情况的每种边顶多遍历一次——之后再来就没有意义了，所以其实也是可以优化的对吧 qwq！
当然，为了避免重复遍历同一位置的同种时间，考虑维护 set 表示从某个机场出发能抵达的所有没有去过的其他机场的其他时间，去了一个就要把对应的那个从 set 移除防止重复遍历！
这样应该就是整个过程了吧！

